const data = $input.first().json;
const body = data.body || data;

const templateName = (body.template_name || '').toLowerCase().trim();
const email = body.email || '';
const nombre = body.nombre || '';
const leadId = body.lead_id || '';
const fechaCita = body.fecha_cita || '';
const closerName = body.closer_name || 'el equipo de Psycoboost';
const bookingUrl = 'https://app.cal.eu/ventas-pb/discovery-call';

const validTemplates = ['bienvenida', 'confirmacion', 'recordatorio_24h', 'recordatorio_1h', 'noshow'];

if (!email) {
  return [{ json: { skip: true, reason: 'no_email' } }];
}

if (!validTemplates.includes(templateName)) {
  return [{ json: { skip: true, reason: 'invalid_template: ' + templateName } }];
}

return [{ json: {
  skip: false,
  templateName,
  email,
  nombre,
  leadId,
  fechaCita,
  closerName,
  bookingUrl
} }];

const d = $json;
const nombre = d.nombre || 'profesional';
const bookingUrl = d.bookingUrl;
const fechaCita = d.fechaCita || '';
const closerName = d.closerName;

// Common styles
const styles = `
  body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background: #f7f7f7; margin: 0; padding: 0; }
  .container { max-width: 600px; margin: 0 auto; background: #ffffff; border-radius: 12px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.08); }
  .header { background: linear-gradient(135deg, #6C63FF 0%, #4834d4 100%); padding: 32px 24px; text-align: center; }
  .header h1 { color: #ffffff; font-size: 24px; margin: 0; font-weight: 700; }
  .header p { color: rgba(255,255,255,0.85); font-size: 14px; margin: 8px 0 0; }
  .body-content { padding: 32px 24px; color: #333; line-height: 1.6; font-size: 15px; }
  .body-content h2 { color: #4834d4; font-size: 20px; margin-top: 0; }
  .cta-btn { display: inline-block; background: #6C63FF; color: #ffffff !important; text-decoration: none; padding: 14px 32px; border-radius: 8px; font-weight: 600; font-size: 16px; margin: 16px 0; }
  .footer { background: #f0f0f0; padding: 20px 24px; text-align: center; font-size: 12px; color: #888; }
  .footer a { color: #6C63FF; text-decoration: none; }
  .highlight { background: #f0eeff; border-left: 4px solid #6C63FF; padding: 12px 16px; border-radius: 4px; margin: 16px 0; }
`;

const footer = `
  <div class="footer">
    <p>Psycoboost - Ayudamos a psicologos a llenar su agenda</p>
    <p><a href="mailto:admin@psycoboost.com">admin@psycoboost.com</a> | <a href="https://wa.me/34982685874">WhatsApp</a></p>
    <p style="margin-top:8px;">Si no deseas recibir mas emails, responde a este mensaje con BAJA</p>
  </div>
`;

let subject = '';
let htmlBody = '';

switch (d.templateName) {
  case 'bienvenida':
    subject = 'Bienvenido/a a Psycoboost, ' + nombre;
    htmlBody = `
      <div class="body-content">
        <h2>Hola ${nombre},</h2>
        <p>Gracias por tu interes en Psycoboost. Nos dedicamos a ayudar a psicologos como tu a tener la agenda llena de pacientes.</p>
        <p>En breve, un miembro de nuestro equipo se pondra en contacto contigo para conocer tu situacion y ver como podemos ayudarte.</p>
        <div class="highlight">
          <strong>Mientras tanto:</strong> Si quieres adelantar y agendar directamente tu sesion de discovery call gratuita, haz clic aqui:
        </div>
        <p style="text-align:center;"><a href="${bookingUrl}" class="cta-btn">Agendar mi sesion</a></p>
        <p>Un saludo,<br><strong>El equipo de Psycoboost</strong></p>
      </div>
    `;
    break;

  case 'confirmacion':
    subject = 'Tu sesion esta confirmada - Psycoboost';
    htmlBody = `
      <div class="body-content">
        <h2>Sesion confirmada!</h2>
        <p>Hola ${nombre},</p>
        <p>Tu discovery call con ${closerName} esta confirmada.</p>
        ${fechaCita ? '<div class="highlight"><strong>Fecha y hora:</strong> ' + fechaCita + '</div>' : ''}
        <p>Prepara cualquier pregunta que tengas sobre como podemos ayudarte a captar mas pacientes. Esta sesion es totalmente gratuita y sin compromiso.</p>
        <p><strong>Consejos para la sesion:</strong></p>
        <ul>
          <li>Busca un lugar tranquilo donde puedas hablar con calma</li>
          <li>Ten a mano datos sobre tu situacion actual (numero de pacientes, fuentes de captacion, etc.)</li>
          <li>Piensa en tus objetivos a 3-6 meses</li>
        </ul>
        <p>Si necesitas cambiar la hora, escribenos a <a href="mailto:admin@psycoboost.com">admin@psycoboost.com</a> o por <a href="https://wa.me/34982685874">WhatsApp</a>.</p>
        <p>Un saludo,<br><strong>El equipo de Psycoboost</strong></p>
      </div>
    `;
    break;

  case 'recordatorio_24h':
    subject = 'Recordatorio: Tu sesion es manana - Psycoboost';
    htmlBody = `
      <div class="body-content">
        <h2>Tu sesion es manana!</h2>
        <p>Hola ${nombre},</p>
        <p>Te recordamos que manana tienes tu discovery call con ${closerName}.</p>
        ${fechaCita ? '<div class="highlight"><strong>Fecha y hora:</strong> ' + fechaCita + '</div>' : ''}
        <p>Estamos deseando hablar contigo y mostrarte como otros psicologos han conseguido llenar su agenda.</p>
        <p>Si necesitas reprogramar, no hay problema: escribenos a <a href="mailto:admin@psycoboost.com">admin@psycoboost.com</a> o por <a href="https://wa.me/34982685874">WhatsApp</a>.</p>
        <p>Hasta manana!<br><strong>El equipo de Psycoboost</strong></p>
      </div>
    `;
    break;

  case 'recordatorio_1h':
    subject = 'En 1 hora: Tu sesion con Psycoboost';
    htmlBody = `
      <div class="body-content">
        <h2>En 1 hora empieza tu sesion!</h2>
        <p>Hola ${nombre},</p>
        <p>Solo queriamos recordarte que en aproximadamente 1 hora tienes tu discovery call con ${closerName}.</p>
        ${fechaCita ? '<div class="highlight"><strong>Hora:</strong> ' + fechaCita + '</div>' : ''}
        <p>Asegurate de estar en un lugar tranquilo y con buena conexion. Te llamaremos al numero que nos facilitaste.</p>
        <p>Te esperamos!<br><strong>El equipo de Psycoboost</strong></p>
      </div>
    `;
    break;

  case 'noshow':
    subject = 'Te hemos echado de menos - Psycoboost';
    htmlBody = `
      <div class="body-content">
        <h2>Hola ${nombre},</h2>
        <p>Hoy teniamos programada tu discovery call pero no hemos podido conectar contigo. No pasa nada, sabemos que a veces surgen imprevistos.</p>
        <p>Si sigues interesado/a en descubrir como otros psicologos han llenado su agenda con nuestro metodo, puedes reagendar facilmente:</p>
        <p style="text-align:center;"><a href="${bookingUrl}" class="cta-btn">Reagendar mi sesion</a></p>
        <p>Si tienes cualquier pregunta, estamos aqui para ti.</p>
        <p>Un saludo,<br><strong>El equipo de Psycoboost</strong></p>
      </div>
    `;
    break;
}

const fullHtml = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><style>${styles}</style></head>
<body>
  <div class="container">
    <div class="header">
      <h1>Psycoboost</h1>
      <p>Llenamos la agenda de tu consulta</p>
    </div>
    ${htmlBody}
    ${footer}
  </div>
</body>
</html>`;

return [{ json: {
  ...d,
  subject,
  htmlBody: fullHtml
} }];
